	normalMap: normalMap
} );
mesh = new THREE.Mesh( geometry, material );
mesh.position.x = 1;
mesh.position.y = 1;
group.add( mesh );

material = new THREE.MeshStandardMaterial( {
	map: normalMap5
} );
mesh = new THREE.Mesh( geometry, material );
mesh.position.x = 1;
mesh.position.y = 3;
group.add( mesh );

